//
import { ORDINAL_DATATYPE } from '../core/datatype-constants';
import { _legendType } from '../legend/legend-renderer-helpers';
import { rendererBoundUtils } from '../plot/renderer-bound-utils';

export function fontRangeParser(encodeType, index, config, chart) {
    let dataSet = chart.dataset,
        dataType = dataSet.getDataType(encodeType, index),
        { ranges, sizes: userSizes } = config,
        bound = rendererBoundUtils.getAvailableBound(chart.plotarea, config),
        rangeOperators = {};

    if (userSizes) {
        rangeOperators.userRanges = {
            size: userSizes,
            plotBound: bound,
            callbackArgs: [chart, bound]
        };
        return rangeOperators;
    }

    rangeOperators.baseSize = {
        config,
        size: ['2%', '20%'],
        plotBound: bound,
        callbackArgs: [chart, bound]
    };

    if (ranges || dataType === ORDINAL_DATATYPE) {
        rangeOperators.mapDiscreteDomainToRange = { ranges };
    } else {
        rangeOperators.mapContinuousDomainToRange = {};
    }

    return rangeOperators;
}
